sql:
SELECT name, description, marker_type
FROM markers
WHERE marker_id = 0;

SELECT name
FROM experiments
WHERE instrument_id > (SELECT AVG(instrument_id) FROM experiments);

external_knowledge:
- 'specific marker' refers to a marker with marker_id 1;
- 'certain instrument' refers to the instrument named 'Instrument 1';
- 'particular patient' refers to the patient with patient_id 0.
